/**
 * Generate FlightAware AeroAPI firewall config.
 *
 * Data source: https://www.flightaware.com/aeroapi/portal/documentation
 *
 * FlightAware AeroAPI authenticates with an API key passed in the
 * `x-apikey` request header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.flightaware.com/aeroapi/portal/documentation";
const PLACEHOLDER_VALUE = "Coffee5afe10ca1Coffee5afe10ca1Co";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from FlightAware AeroAPI docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:flightaware",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const flightawareFirewall = {",
    '  name: "flightaware",',
    '  description: "FlightAware AeroAPI",',
    "  placeholders: {",
    `    FLIGHTAWARE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://aeroapi.flightaware.com",',
    "      auth: {",
    "        headers: {",
    '          "x-apikey": "${{ secrets.FLIGHTAWARE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating FlightAware AeroAPI firewall config...");
  const ts = generateTypeScript();
  writeOutput("flightaware", ts, import.meta.dirname);
}
